import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"📊 市場情緒日報 — 2026-05-03","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_20260503.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_20260503.md"}'),s={name:"Deep32Q知識庫/市場情緒/市場情緒_20260503.md"};function i(n,e,l,h,c,m){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="📊-市場情緒日報-—-2026-05-03" tabindex="-1">📊 市場情緒日報 — 2026-05-03 <a class="header-anchor" href="#📊-市場情緒日報-—-2026-05-03" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026-05-03&quot;">​</a></h1><blockquote><p>掃描時間：2026-05-03 Asia/Taipei 05:02 資料來源：web_search (Google Search grounding)</p></blockquote><hr><h2 id="🌍-全球財經頭條-5-條" tabindex="-1">🌍 全球財經頭條（5 條） <a class="header-anchor" href="#🌍-全球財經頭條-5-條" aria-label="Permalink to &quot;🌍 全球財經頭條（5 條）&quot;">​</a></h2><h3 id="_1-🇺🇸-s-p-500-續創高-apple-財報-iphone-17-中國熱賣" tabindex="-1">1. 🇺🇸 S&amp;P 500 續創高，Apple 財報 iPhone 17 中國熱賣 <a class="header-anchor" href="#_1-🇺🇸-s-p-500-續創高-apple-財報-iphone-17-中國熱賣" aria-label="Permalink to &quot;1. 🇺🇸 S&amp;P 500 續創高，Apple 財報 iPhone 17 中國熱賣&quot;">​</a></h3><p>5/1 美股續漲，S&amp;P 500 +0.4%、道瓊 +0.3%、納斯達克 +0.6%。Apple Q2 營收年增 17%（iPhone 17 中國銷售強勁 + 服務營收 $310 億創紀錄）。WWDC 2026 即將召開，AI 軟體更新受矚。 <em>來源：Pique News (2026-05-01) — <a href="https://www.piquenewsmagazine.com/the-mix/us-stocks-drift-higher-and-oil-prices-hold-steady-as-many-world-markets-are-closed-for-may-day-12221743" target="_blank" rel="noreferrer">https://www.piquenewsmagazine.com/the-mix/us-stocks-drift-higher-and-oil-prices-hold-steady-as-many-world-markets-are-closed-for-may-day-12221743</a>, FXLeaders (2026-05-02)</em></p><h3 id="_2-🛢️-油價波動加劇-斯洛伐克總理批-trump-言論擾市" tabindex="-1">2. 🛢️ 油價波動加劇，斯洛伐克總理批 Trump 言論擾市 <a class="header-anchor" href="#_2-🛢️-油價波動加劇-斯洛伐克總理批-trump-言論擾市" aria-label="Permalink to &quot;2. 🛢️ 油價波動加劇，斯洛伐克總理批 Trump 言論擾市&quot;">​</a></h3><p>布蘭特原油一度衝破 $126 後回落至 $111。斯洛伐克總理 Fico 公開批評 Trump 言論導致油價劇烈波動。荷莫茲第 64 天封閉，美國汽油均價達 <strong>$4.39/加侖</strong>。EIA 預測布蘭特 Q2 均價 $115。 <em>來源：WeeklyBlitz (2026-05-03) — <a href="https://weeklyblitz.net/2026/05/03/slovak-pm-fico-blames-trumps-rhetoric-for-volatile-global-oil-prices/" target="_blank" rel="noreferrer">https://weeklyblitz.net/2026/05/03/slovak-pm-fico-blames-trumps-rhetoric-for-volatile-global-oil-prices/</a>, CBS News</em></p><h3 id="_3-🏛️-全球經濟「4-8-週關鍵窗口」-經濟學家警告衰退風險" tabindex="-1">3. 🏛️ 全球經濟「4-8 週關鍵窗口」，經濟學家警告衰退風險 <a class="header-anchor" href="#_3-🏛️-全球經濟「4-8-週關鍵窗口」-經濟學家警告衰退風險" aria-label="Permalink to &quot;3. 🏛️ 全球經濟「4-8 週關鍵窗口」，經濟學家警告衰退風險&quot;">​</a></h3><p>知名經濟學家警告僅有 4-8 週時間避免全球衰退，關鍵在於重開石油航線（荷莫茲）。美國 Q1 GDP 年化 2.0%，PCE 價格指數 Q1 增 4.5%。聯準會鮑爾最後一次會議（8-4 投票分歧）。 <em>來源：Economictimes (2026-05-03) — <a href="https://economictimes.indiatimes.com/news/international/us/one-of-the-worlds-top-economists-just-dropped-a-chilling-8-week-recession-ultimatum-heres-what-must-happen-now/articleshow/130679072.cms" target="_blank" rel="noreferrer">https://economictimes.indiatimes.com/news/international/us/one-of-the-worlds-top-economists-just-dropped-a-chilling-8-week-recession-ultimatum-heres-what-must-happen-now/articleshow/130679072.cms</a>, BEA</em></p><h3 id="_4-🥇-金價-4-600-4-661-波動-fomc-鷹派但避險買盤支撐" tabindex="-1">4. 🥇 金價 $4,600-4,661 波動，FOMC 鷹派但避險買盤支撐 <a class="header-anchor" href="#_4-🥇-金價-4-600-4-661-波動-fomc-鷹派但避險買盤支撐" aria-label="Permalink to &quot;4. 🥇 金價 $4,600-4,661 波動，FOMC 鷹派但避險買盤支撐&quot;">​</a></h3><p>5/1 COMEX 金期收 <strong>$4,661.40</strong>（+0.32%），現貨約 $4,600。FOMC 4/29 鷹派不降息一度使金價承壓，但買家於 $4,500 進場支撐。UBS 維持年底 $5,900 預測。 <em>來源：GoldPrice.org (2026-05-02) — <a href="https://goldprice.org/news/hawkish-fomc-pressures-gold-buyers-defend-4500-support" target="_blank" rel="noreferrer">https://goldprice.org/news/hawkish-fomc-pressures-gold-buyers-defend-4500-support</a>, TradingEconomics</em></p><h3 id="_5-🌐-加拿大總理-carney-歐洲峰會推廣投資" tabindex="-1">5. 🌐 加拿大總理 Carney 歐洲峰會推廣投資 <a class="header-anchor" href="#_5-🌐-加拿大總理-carney-歐洲峰會推廣投資" aria-label="Permalink to &quot;5. 🌐 加拿大總理 Carney 歐洲峰會推廣投資&quot;">​</a></h3><p>Mark Carney 在歐洲政治峰會推廣加拿大投資，試圖分散全球地緣風險。全球資本市場 5 月進入「轉型期」而非「解決期」，通膨威脅持續。 <em>來源：CBC (2026-05-03) — <a href="https://www.cbc.ca/radio/sunday/the-sunday-magazine-may-3-2026-9.7184387" target="_blank" rel="noreferrer">https://www.cbc.ca/radio/sunday/the-sunday-magazine-may-3-2026-9.7184387</a>, Seeking Alpha</em></p><hr><h2 id="🇹🇼-台灣財經頭條-5-條" tabindex="-1">🇹🇼 台灣財經頭條（5 條） <a class="header-anchor" href="#🇹🇼-台灣財經頭條-5-條" aria-label="Permalink to &quot;🇹🇼 台灣財經頭條（5 條）&quot;">​</a></h2><h3 id="_1-👑-全球半導體市場-2026-年突破-1-兆美元-台灣產值估-7-1-兆創高" tabindex="-1">1. 👑 全球半導體市場 2026 年突破 1 兆美元，台灣產值估 7.1 兆創高 <a class="header-anchor" href="#_1-👑-全球半導體市場-2026-年突破-1-兆美元-台灣產值估-7-1-兆創高" aria-label="Permalink to &quot;1. 👑 全球半導體市場 2026 年突破 1 兆美元，台灣產值估 7.1 兆創高&quot;">​</a></h3><p>2026 年全球半導體市場預計突破 <strong>1 兆美元</strong>。台灣半導體產值估 <strong>7.1 兆元</strong>（年增 24.4%）。AI 晶片與 HBM 為雙引擎。 <em>來源：Storm.mg (2026-05-03) — <a href="https://www.storm.mg/article/11125995" target="_blank" rel="noreferrer">https://www.storm.mg/article/11125995</a></em></p><h3 id="_2-🏭-台積電-3nm-滿載、2nm-量產貢獻營收-通吃-ai-晶片訂單" tabindex="-1">2. 🏭 台積電 3nm 滿載、2nm 量產貢獻營收，通吃 AI 晶片訂單 <a class="header-anchor" href="#_2-🏭-台積電-3nm-滿載、2nm-量產貢獻營收-通吃-ai-晶片訂單" aria-label="Permalink to &quot;2. 🏭 台積電 3nm 滿載、2nm 量產貢獻營收，通吃 AI 晶片訂單&quot;">​</a></h3><p>台積電 3 奈米持續滿載，2 奈米上線量產。2025 Q4 全球晶圓代工市佔率 <strong>70.4%</strong>。廠務供應鏈漢唐、帆宣等 2025 獲利創高。半導體特化材料和設備在地化成為贏家。 <em>來源：CTEE (2026-05-03)</em></p><h3 id="_3-💾-ai-記憶體超級週期-dram-市場近乎倍增" tabindex="-1">3. 💾 AI 記憶體超級週期，DRAM 市場近乎倍增 <a class="header-anchor" href="#_3-💾-ai-記憶體超級週期-dram-市場近乎倍增" aria-label="Permalink to &quot;3. 💾 AI 記憶體超級週期，DRAM 市場近乎倍增&quot;">​</a></h3><p>NAND 快閃最高成長 <strong>4 倍</strong>。一台 AI 伺服器 DRAM 用量為一般伺服器 8 倍。SanDisk 財報亮眼上調目標價。 <em>來源：LTN (2026-05-03) — <a href="https://ec.ltn.com.tw/article/paper/1735042" target="_blank" rel="noreferrer">https://ec.ltn.com.tw/article/paper/1735042</a></em></p><h3 id="_4-🔄-半導體通膨成形-晶圓代工-封測-ic-設計齊漲" tabindex="-1">4. 🔄 半導體通膨成形：晶圓代工/封測/IC 設計齊漲 <a class="header-anchor" href="#_4-🔄-半導體通膨成形-晶圓代工-封測-ic-設計齊漲" aria-label="Permalink to &quot;4. 🔄 半導體通膨成形：晶圓代工/封測/IC 設計齊漲&quot;">​</a></h3><p>力積電、世界先進、聯電調漲代工價格，後段封測跟漲。IC 設計廠也決定調漲產品售價反映成本。ASIC 走向 GPU+ASIC 雙主流。 <em>來源：TechNews (2026-05-01) — <a href="https://finance.technews.tw/2026/05/01/semiconductor-inflation-trend-takes-shape-wafer-foundries-ic-design-price-hikes/" target="_blank" rel="noreferrer">https://finance.technews.tw/2026/05/01/semiconductor-inflation-trend-takes-shape-wafer-foundries-ic-design-price-hikes/</a></em></p><h3 id="_5-🇪🇺-台歐半導體關係深化-歐盟視台灣為戰略夥伴" tabindex="-1">5. 🇪🇺 台歐半導體關係深化，歐盟視台灣為戰略夥伴 <a class="header-anchor" href="#_5-🇪🇺-台歐半導體關係深化-歐盟視台灣為戰略夥伴" aria-label="Permalink to &quot;5. 🇪🇺 台歐半導體關係深化，歐盟視台灣為戰略夥伴&quot;">​</a></h3><p>歐盟有意將台歐關係轉向以經濟安全、供應鏈韌性為核心的戰略夥伴關係。台灣在 AI 基礎設施領域的戰略核心地位獲認可。高盛預期台股未來 12 個月上看 <strong>30,200 點</strong>。 <em>來源：UDN (2026-05-03) — <a href="https://money.udn.com/money/story/5607/9478315" target="_blank" rel="noreferrer">https://money.udn.com/money/story/5607/9478315</a>, wealth.com.tw</em></p><hr><h2 id="📊-市場情緒判斷" tabindex="-1">📊 市場情緒判斷 <a class="header-anchor" href="#📊-市場情緒判斷" aria-label="Permalink to &quot;📊 市場情緒判斷&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">判斷</th><th style="text-align:left;">理由</th></tr></thead><tbody><tr><td style="text-align:center;">🟢 <strong>偏多</strong></td><td style="text-align:left;">半導體 1 兆美元里程碑、AI 長線 20 年趨勢、台積電 70% 市佔；但 4-8 週衰退警告、油價波動、聯準會換帥不確定。</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Pique News (2026-05-01): S&amp;P 續創高 — <a href="https://www.piquenewsmagazine.com/the-mix/us-stocks-drift-higher-and-oil-prices-hold-steady-as-many-world-markets-are-closed-for-may-day-12221743" target="_blank" rel="noreferrer">https://www.piquenewsmagazine.com/the-mix/us-stocks-drift-higher-and-oil-prices-hold-steady-as-many-world-markets-are-closed-for-may-day-12221743</a></li><li>WeeklyBlitz (2026-05-03): Fico 批油價擾市 — <a href="https://weeklyblitz.net/2026/05/03/slovak-pm-fico-blames-trumps-rhetoric-for-volatile-global-oil-prices/" target="_blank" rel="noreferrer">https://weeklyblitz.net/2026/05/03/slovak-pm-fico-blames-trumps-rhetoric-for-volatile-global-oil-prices/</a></li><li>Economictimes (2026-05-03): 4-8 週衰退警告 — <a href="https://economictimes.indiatimes.com/news/international/us/one-of-the-worlds-top-economists-just-dropped-a-chilling-8-week-recession-ultimatum-heres-what-must-happen-now/articleshow/130679072.cms" target="_blank" rel="noreferrer">https://economictimes.indiatimes.com/news/international/us/one-of-the-worlds-top-economists-just-dropped-a-chilling-8-week-recession-ultimatum-heres-what-must-happen-now/articleshow/130679072.cms</a></li><li>GoldPrice (2026-05-02): 金價 FOMC — <a href="https://goldprice.org/news/hawkish-fomc-pressures-gold-buyers-defend-4500-support" target="_blank" rel="noreferrer">https://goldprice.org/news/hawkish-fomc-pressures-gold-buyers-defend-4500-support</a></li><li>CBC (2026-05-03): Carney 歐洲 — <a href="https://www.cbc.ca/radio/sunday/the-sunday-magazine-may-3-2026-9.7184387" target="_blank" rel="noreferrer">https://www.cbc.ca/radio/sunday/the-sunday-magazine-may-3-2026-9.7184387</a></li><li>Storm.mg (2026-05-03): 半導體 1 兆美元 — <a href="https://www.storm.mg/article/11125995" target="_blank" rel="noreferrer">https://www.storm.mg/article/11125995</a></li><li>TechNews (2026-05-01): 半導體通膨 — <a href="https://finance.technews.tw/2026/05/01/semiconductor-inflation-trend-takes-shape-wafer-foundries-ic-design-price-hikes/" target="_blank" rel="noreferrer">https://finance.technews.tw/2026/05/01/semiconductor-inflation-trend-takes-shape-wafer-foundries-ic-design-price-hikes/</a></li><li>UDN (2026-05-03): 台歐半導體 — <a href="https://money.udn.com/money/story/5607/9478315" target="_blank" rel="noreferrer">https://money.udn.com/money/story/5607/9478315</a></li><li>LTN (2026-05-03): 記憶體超級週期 — <a href="https://ec.ltn.com.tw/article/paper/1735042" target="_blank" rel="noreferrer">https://ec.ltn.com.tw/article/paper/1735042</a></li><li>BEA (2026-04-30): 美國 Q1 GDP 2.0% — <a href="https://www.bea.gov/news/2026/gdp-advance-estimate-1st-quarter-2026" target="_blank" rel="noreferrer">https://www.bea.gov/news/2026/gdp-advance-estimate-1st-quarter-2026</a></li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 抓取時間：2026-05-03 Asia/Taipei 05:02</em></p>',34)])])}const w=a(s,[["render",i]]);export{d as __pageData,w as default};
